// Custom heavy projectile for the bullet-hell boss: a roiling void orb.
// Layered void shell + astral rim + a molten-cool glowing core with catch-light.
defineSprite('g_voidorb', 10, 10, (p) => {
  // outer energy bloom (soft, gets caught under the dark outline for a halo)
  p.glow(5, 5, 5, P.astral, 0.4, 4);
  // void shell, 3 tonal steps + a cool astral rim ring
  p.ellipse(5, 5, 4.5, 4.5, P.void);
  p.ellipse(5, 5, 3.7, 3.7, P.purpleD);
  p.ring(5, 5, 4.2, withAlpha(P.astralL, 0.6));
  p.ellipse(5, 5, 2.7, 2.7, P.purple);
  p.ellipse(5, 5, 1.8, 1.8, P.purpleL);
  // hot magical core glow + specular catch-light (top-left light source)
  p.glow(4.5, 4, 2.2, P.manaL, 0.7, 3);
  p.px(4, 3, P.white); p.px(5, 3, P.rimCool);
  // a couple of orbiting energy specks for a "roiling" feel
  p.px(8, 6, withAlpha(P.astralL, 0.8));
  p.px(2, 5, withAlpha(P.manaL, 0.7));
  p.rimLight(P.rimCool, 0.5);
  p.outline(P.ink);
}, { anchor: [5, 5] });

// ---------------------------------------------------------------------------
// BOSS 1 — 虛空巫王 (Void Sovereign). Bullet-hell shooter. 36x40, feet anchored.
// A levitating robed archmage crowned with a halo of shards, trailing void.
// Upgraded: gradient robe, astral aura, glowing rune seam, big burning eyes
// with catch-lights, conjured palm orbs with glow, shimmering shard halo.
// ---------------------------------------------------------------------------
defineAnim('g_voidsovereign', 36, 40, 4, (p, f) => {
  const breath = (f === 1 || f === 3) ? 1 : 0;          // slow hover bob
  const oy = -breath;
  const halo = (f % 4) * 0.6;                            // crown shimmer phase
  const phase = f / 4;                                   // 0..1 aura pulse
  const eyeCol = (f % 2) ? P.manaL : P.astralL;          // flicker between tones

  // ---- back aura: pulsing astral halo behind the whole boss ----
  p.aura(18, 18 + oy, 14, P.astral, phase, 2);
  p.glow(18, 16 + oy, 11, P.void, 0.5, 4);

  // ---- ground void wisps (tattered robe hem, no legs — it floats) ----
  for (let i = 0; i < 5; i++) {
    const tx = 8 + i * 5;
    const tlen = 36 + ((i + f) % 2) * 2 + oy;
    p.vline(31 + oy, tlen, tx, P.void);
    p.vline(31 + oy, tlen - 2, tx, P.purpleD);
    p.px(tx, tlen, withAlpha(P.astralL, 0.6));           // wisp tip glint
  }
  p.softShadow(18, 37 + oy, 12, 3, 0.5, P.void);         // shadow pool of energy
  p.glow(18, 36 + oy, 7, P.astral, 0.3, 3);

  // ---- robe body (broad trapezoid) with vertical gradient shading ----
  const top = 16 + oy, bot = 35 + oy;
  for (let y = top; y <= bot; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(5 + t * 9);
    p.hline(18 - hw, 17 + hw, y, mix(P.purpleD, P.void, t * 0.5));
  }
  // lit inner panel (lighter core, top-lit)
  for (let y = top + 1; y <= bot - 2; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(3 + t * 5);
    p.hline(18 - hw, 17 + hw, y, mix(P.purple, P.purpleD, t * 0.6));
  }
  // left-side highlight column (top-left light source) + right-side shade
  p.vline(top + 1, bot - 2, 18 - 3, withAlpha(P.purpleL, 0.5));
  // glowing rune seam down the chest
  p.vline(top + 2, bot - 2, 18, P.manaL);
  p.glow(18, top + 8, 3, P.astralL, 0.4, 3);
  p.sparkle(18, top + 5, P.white, 1);
  p.px(18, top + 11, P.holyL); p.px(18, bot - 4, P.white);
  // crackling rune glyphs on the robe (anime sigils)
  p.px(15, top + 7, P.astralL); p.px(21, top + 7, P.astralL);
  p.px(14, top + 13, P.manaL); p.px(22, top + 13, P.manaL);
  // hem trim
  p.hline(5, 30, bot - 1, P.purpleL);
  p.hline(7, 28, bot, P.void);

  // ---- shoulders / arms with wide sleeves ----
  p.ellipse(8, 19 + oy, 4, 4, P.purpleD);
  p.ellipse(28, 19 + oy, 4, 4, P.purpleD);
  p.ellipse(8, 18 + oy, 2.6, 2.6, P.purple);
  p.ellipse(28, 18 + oy, 2.6, 2.6, P.purple);
  p.px(7, 17 + oy, P.purpleL); p.px(27, 17 + oy, P.purpleL);   // shoulder sheen
  // sleeves dropping to clawed hands cupping orbs
  p.rect(4, 21 + oy, 3, 7, P.purpleD);
  p.rect(29, 21 + oy, 3, 7, P.purpleD);
  p.vline(21 + oy, 27 + oy, 4, withAlpha(P.purpleL, 0.5));     // sleeve light edge
  // conjured orbs in palms (glow + bright core)
  p.glow(5, 28 + oy, 3, P.astral, 0.55, 3);
  p.glow(30, 28 + oy, 3, P.astral, 0.55, 3);
  p.ellipse(5, 28 + oy, 1.7, 1.7, P.manaL); p.px(5, 28 + oy, P.white);
  p.ellipse(30, 28 + oy, 1.7, 1.7, P.manaL); p.px(30, 28 + oy, P.white);
  p.px(4, 27 + oy, P.holyL); p.px(29, 27 + oy, P.holyL);

  // ---- hooded head ----
  p.ellipse(18, 11 + oy, 7, 7, P.purpleD);
  p.ellipse(18, 10 + oy, 5.4, 5.4, mix(P.purple, P.purpleD, 0.3));
  p.ellipse(18, 7 + oy, 3.6, 2.4, P.purpleL);           // top sheen
  p.px(15, 6 + oy, P.rim);                              // hood rim glint
  // face void
  p.rect(13, 10 + oy, 10, 6, P.void);
  p.ellipse(18, 13 + oy, 4.5, 3, P.shadow);
  // burning eyes (glow + bright core + white catch-light)
  p.glow(15, 13 + oy, 2.4, eyeCol, 0.7, 3);
  p.glow(21, 13 + oy, 2.4, eyeCol, 0.7, 3);
  p.rect(14, 12 + oy, 3, 2, eyeCol); p.rect(19, 12 + oy, 3, 2, eyeCol);
  p.px(15, 12 + oy, P.white); p.px(20, 12 + oy, P.white);
  p.px(14, 13 + oy, P.astralL); p.px(21, 13 + oy, P.astralL);

  // ---- floating crown of shards (the halo) ----
  for (let i = 0; i < 5; i++) {
    const ang = -Math.PI + (i / 4) * Math.PI;            // arc over the head
    const cx = Math.round(18 + Math.cos(ang) * 9);
    const cy = Math.round(4 + oy + Math.sin(ang) * 3 + Math.sin(halo + i) * 0.5);
    p.vline(cy - 2, cy + 1, cx, P.shardD);
    p.px(cx, cy - 2, P.shardL);
    p.px(cx, cy - 1, P.shard);
    p.px(cx, cy + 1, withAlpha(P.shardL, 0.5));          // shard under-glow
  }
  // central tall shard
  p.vline(1 + oy, 5 + oy, 18, P.shardD);
  p.vline(2 + oy, 5 + oy, 18, P.shard);
  p.px(18, 1 + oy, P.white);
  p.glow(18, 3 + oy, 2.5, P.shardL, 0.5, 3);

  // ---- kira sparkle accents (frame-varied) ----
  if (f === 0 || f === 2) p.star4(30, 8 + oy, 2, P.astralL, P.white);
  if (f === 1 || f === 3) p.star4(6, 6 + oy, 2, P.shardL, P.white);

  p.rimLight(P.rimCool, 0.5);
  p.outline(P.ink);
}, { anchor: [18, 38], fps: 4 });

defineIcon('g_voidsovereign_icon', P.void, (p) => {
  // hooded silhouette with glowing eyes + shard crown
  p.glow(8, 9, 6, P.astral, 0.4, 3);
  p.ellipse(8, 9, 4.5, 4.5, P.purpleD);
  p.ellipse(8, 8, 3.2, 3.2, mix(P.purple, P.purpleD, 0.3));
  p.px(6, 6, P.purpleL);
  p.rect(6, 8, 5, 4, P.void);
  p.glow(6, 9, 1.6, P.manaL, 0.7, 2); p.glow(9, 9, 1.6, P.manaL, 0.7, 2);
  p.px(6, 9, P.white); p.px(9, 9, P.white);
  p.vline(2, 4, 8, P.shardL); p.px(5, 4, P.shard); p.px(11, 4, P.shard);
  p.px(8, 2, P.white);
  p.star4(12, 4, 1, P.astralL, P.white);
});

