// BOSS 2 — 熔岩巨獸 (Magma Colossus). High-HP charger. 38x36, feet anchored.
// A hulking molten golem; cracked obsidian plates over a furnace-glow core.
// Upgraded: heat-haze aura, layered furnace core (p.glow), branching glowing
// lava veins, ember specks, top-lit obsidian plates, rim light on rock edges.
// ---------------------------------------------------------------------------
defineAnim('g_magmacolossus', 38, 36, 4, (p, f) => {
  const stomp = (f === 1) ? 1 : (f === 3) ? -1 : 0;     // weight-shift sway
  const oy = (f === 2) ? -1 : 0;                         // heavy breathing rise
  const glow = (f % 2) ? P.emberL : P.ember;            // pulsing core
  const phase = f / 4;                                  // 0..1 heat pulse

  const rock = P.gray1, rockD = darken(P.gray1, 0.35), rockL = P.gray2;
  const rockHi = lighten(P.gray2, 0.18);

  // ---- heat aura / glow behind the colossus ----
  p.glow(19, 21 + oy, 16, P.blood, 0.35, 4);
  p.aura(19, 21 + oy, 15, P.ember, phase, 2);

  // ---- contact shadow first (under the feet) ----
  p.softShadow(19, 35, 14, 3, 0.5);
  p.glow(19, 35, 9, P.ember, 0.3, 3);                   // molten ground spill

  // ---- legs / feet (thick pillars) ----
  p.rect(8 + stomp, 28 + oy, 7, 8, rockD);
  p.rect(23 - stomp, 28 + oy, 7, 8, rockD);
  p.rect(9 + stomp, 29 + oy, 5, 6, rock);
  p.rect(24 - stomp, 29 + oy, 5, 6, rock);
  p.hline(9 + stomp, 13 + stomp, 29 + oy, rockHi);      // top-lit knee edge
  p.hline(24 - stomp, 28 - stomp, 29 + oy, rockHi);
  // molten cracks in legs (glowing)
  p.vline(30 + oy, 34 + oy, 11 + stomp, glow);
  p.vline(30 + oy, 34 + oy, 26 - stomp, P.ember);
  p.px(11 + stomp, 31 + oy, P.white); p.px(26 - stomp, 31 + oy, P.emberL);

  // ---- torso (massive boulder block) ----
  p.rect(6, 12 + oy, 26, 18, rockD);
  p.rect(7, 13 + oy, 24, 15, rock);
  p.gradV(8, 13 + oy, 22, 4, rockHi, rock);             // top light edge (graded)
  // shoulder boulders
  p.ellipse(7, 14 + oy, 5, 5, rockD); p.ellipse(31, 14 + oy, 5, 5, rockD);
  p.ellipse(7, 13 + oy, 3, 3, rockL); p.ellipse(31, 13 + oy, 3, 3, rockL);
  p.px(6, 12 + oy, rockHi); p.px(30, 12 + oy, rockHi);  // shoulder specular
  // rocky surface texture (deterministic, won't flicker between bakes)
  p.speckle(8, 14 + oy, 22, 14, rockD, 7, 41);
  p.speckle(9, 15 + oy, 20, 12, rockHi, 4, 17);

  // ---- furnace core (glowing chest cavity) — layered glow ----
  p.glow(19, 21 + oy, 7, P.ember, 0.55, 4);
  p.ellipse(19, 21 + oy, 6, 5, P.blood);
  p.ellipse(19, 21 + oy, 4.6, 3.8, P.redD);
  p.ellipse(19, 21 + oy, 3.2, 2.6, P.ember);
  p.ellipse(19, 20 + oy, 1.8, 1.4, glow);
  p.px(19, 20 + oy, P.white); p.px(18, 19 + oy, P.holyL);
  // lava veins spidering out from the core (hot inner, brighter cracks)
  p.line(19, 16 + oy, 14, 13 + oy, P.ember); p.line(19, 16 + oy, 24, 13 + oy, P.ember);
  p.line(13, 21 + oy, 8, 24 + oy, P.emberL); p.line(25, 21 + oy, 30, 24 + oy, P.emberL);
  p.line(16, 25 + oy, 13, 29 + oy, P.ember); p.line(22, 25 + oy, 25, 29 + oy, P.ember);
  p.px(14, 13 + oy, P.emberL); p.px(24, 13 + oy, P.emberL);   // vein tips
  // obsidian plate cracks (dark)
  p.line(9, 15 + oy, 12, 20 + oy, rockD); p.line(29, 15 + oy, 26, 20 + oy, rockD);

  // ---- arms / massive fists ----
  p.rect(2, 16 + oy, 5, 9, rockD); p.rect(31, 16 + oy, 5, 9, rockD);
  p.rect(3, 17 + oy, 3, 6, rock); p.rect(32, 17 + oy, 3, 6, rock);
  p.vline(17 + oy, 22 + oy, 3, rockHi); p.px(32, 17 + oy, rockHi);  // arm light edge
  p.ellipse(4, 26 + oy, 4, 4, rockD); p.ellipse(34, 26 + oy, 4, 4, rockD);
  p.ellipse(4, 25 + oy, 2.6, 2.6, rock); p.ellipse(34, 25 + oy, 2.6, 2.6, rock);
  p.glow(4, 26 + oy, 2.5, glow, 0.5, 2); p.glow(34, 26 + oy, 2.5, glow, 0.5, 2);
  p.px(4, 26 + oy, glow); p.px(34, 26 + oy, glow);      // knuckle embers
  p.px(4, 25 + oy, P.white); p.px(34, 25 + oy, P.white);

  // ---- head (blocky, sunk into shoulders) ----
  p.rect(13, 5 + oy, 12, 9, rockD);
  p.rect(14, 6 + oy, 10, 7, rock);
  p.gradV(14, 6 + oy, 10, 2, rockHi, rock);
  // brow ridge + burning eyes (glow + catch-light)
  p.rect(13, 9 + oy, 12, 1, rockD);
  p.glow(16, 11 + oy, 2.2, glow, 0.7, 3); p.glow(21, 11 + oy, 2.2, glow, 0.7, 3);
  p.rect(15, 10 + oy, 3, 2, glow); p.rect(20, 10 + oy, 3, 2, glow);
  p.px(16, 10 + oy, P.white); p.px(21, 10 + oy, P.white);
  // gritted molten jaw
  p.hline(15, 23, 13 + oy, P.ember);
  p.px(17, 13 + oy, P.ink); p.px(19, 13 + oy, P.ink); p.px(21, 13 + oy, P.ink);
  // little horn nubs
  p.px(13, 5 + oy, rockL); p.px(24, 5 + oy, rockL);
  p.px(12, 6 + oy, rockD); p.px(25, 6 + oy, rockD);

  // ---- rising ember sparks (frame-varied motion accents) ----
  p.px(10, 10 + oy - (f % 3), withAlpha(P.emberL, 0.8));
  p.px(28, 8 + oy - ((f + 1) % 3), withAlpha(P.ember, 0.8));
  if (f === 1 || f === 3) p.star4(30, 12 + oy, 1, P.emberL, P.white);

  p.rimLight(P.rim, 0.45);
  p.outline(P.ink);
}, { anchor: [19, 35], fps: 5 });

